interface QueuedRequest {
  id: string;             // unique per request, used to update UI when response arrives
  prompt: string;         // the user's message text
  conversationHistory: Array<{ role: 'user' | 'assistant'; content: string }>;
  timestamp: number;      // Date.now() — for display and expiry
  retries: number;        // incremented on failure; drop after MAX_RETRIES
}

const QUEUE_KEY = '@claude_queue';
const MAX_RETRIES = 3;

import AsyncStorage from '@react-native-async-storage/async-storage';

async function loadQueue(): Promise<QueuedRequest[]> {
  try {
    const raw = await AsyncStorage.getItem(QUEUE_KEY);
    return raw ? (JSON.parse(raw) as QueuedRequest[]) : [];
  } catch {
    return [];   // corrupt storage — start fresh rather than crash
  }
}

async function saveQueue(queue: QueuedRequest[]): Promise<void> {
  await AsyncStorage.setItem(QUEUE_KEY, JSON.stringify(queue));
}

async function enqueue(item: QueuedRequest): Promise<void> {
  const queue = await loadQueue();
  queue.push(item);
  await saveQueue(queue);
}

async function dequeue(): Promise<QueuedRequest | null> {
  const queue = await loadQueue();
  if (queue.length === 0) return null;
  const [head, ...rest] = queue;
  await saveQueue(rest);
  return head;
}

async function requeueWithRetry(item: QueuedRequest): Promise<void> {
  if (item.retries + 1 >= MAX_RETRIES) {
    console.warn(`Dropping request ${item.id} after ${MAX_RETRIES} retries`);
    return;   // discard — do not re-add to queue
  }
  const queue = await loadQueue();
  // Put it at the back; could also put at front depending on your UX
  queue.push({ ...item, retries: item.retries + 1 });
  await saveQueue(queue);
}

import NetInfo, { NetInfoState } from '@react-native-community/netinfo';
import { useEffect, useRef, useState } from 'react';

export function useNetworkStatus() {
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => {
    // Fetch current state immediately (the first event may be delayed)
    NetInfo.fetch().then(state => {
      setIsConnected(state.isConnected ?? false);
    });

    // Subscribe to changes
    const unsubscribe = NetInfo.addEventListener((state: NetInfoState) => {
      setIsConnected(state.isConnected ?? false);
    });

    return unsubscribe;   // clean up listener on unmount
  }, []);

  return isConnected;
}

import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.EXPO_PUBLIC_ANTHROPIC_KEY! });

// flushQueue is called every time isConnected flips to true
async function flushQueue(
  onResult: (id: string, text: string) => void
): Promise<void> {
  while (true) {
    const item = await dequeue();
    if (!item) break;  // queue empty

    try {
      const message = await client.messages.create({
        model: 'claude-opus-4-8',
        max_tokens: 1024,
        messages: [
          ...item.conversationHistory,
          { role: 'user', content: item.prompt },
        ],
      });

      const text =
        message.content[0]?.type === 'text' ? message.content[0].text : '';
      onResult(item.id, text);
    } catch (err: any) {
      // Network error mid-flush — re-queue and abort (will retry on next reconnect)
      if (err.status === undefined || err.status >= 500) {
        await requeueWithRetry(item);
        break;
      }
      // 4xx errors (bad request, auth) — don't retry, just notify
      onResult(item.id, `[Error: ${err.message}]`);
    }
  }
}

import { useEffect, useCallback } from 'react';

export function useOfflineClaudeQueue(
  onResult: (id: string, text: string) => void
) {
  const isConnected = useNetworkStatus();

  // When connectivity is restored, flush the persistent queue
  useEffect(() => {
    if (isConnected === true) {
      flushQueue(onResult).catch(console.error);
    }
  }, [isConnected]);

  const send = useCallback(
    async (
      id: string,
      prompt: string,
      conversationHistory: Array<{ role: 'user' | 'assistant'; content: string }>
    ) => {
      if (isConnected === true) {
        // Online path: call Claude directly
        try {
          const message = await client.messages.create({
            model: 'claude-opus-4-8',
            max_tokens: 1024,
            messages: [...conversationHistory, { role: 'user', content: prompt }],
          });
          const text =
            message.content[0]?.type === 'text' ? message.content[0].text : '';
          onResult(id, text);
        } catch {
          // Transient failure: fall through to queue
          await enqueue({ id, prompt, conversationHistory, timestamp: Date.now(), retries: 0 });
        }
      } else {
        // Offline path: persist and show pending state
        await enqueue({ id, prompt, conversationHistory, timestamp: Date.now(), retries: 0 });
      }
    },
    [isConnected, onResult]
  );

  return { send, isConnected };
}

function ChatMessage({ message }: { message: Message }) {
  const label =
    message.status === 'queued'
      ? '⏳ Queued — will send when online'
      : message.status === 'sending'
      ? '...'
      : null;

  return (
    <View style={styles.bubble}>
      <Text>{message.text}</Text>
      {label && (
        <Text style={styles.statusLabel}>{label}</Text>
      )}
    </View>
  );
}

// In the screen component:
const [messages, setMessages] = useState<Message[]>([]);
const { send, isConnected } = useOfflineClaudeQueue(
  (id, text) => {
    setMessages(prev =>
      prev.map(m => (m.id === id ? { ...m, text, status: 'done' } : m))
    );
  }
);

// Banner shown when offline
{isConnected === false && (
  <View style={styles.offlineBanner}>
    <Text style={styles.offlineText}>You are offline. Messages will be sent when you reconnect.</Text>
  </View>
)}

const MAX_QUEUE_SIZE = 50;
const MAX_AGE_MS = 24 * 60 * 60 * 1000;  // 24 hours

async function loadQueue(): Promise<QueuedRequest[]> {
  try {
    const raw = await AsyncStorage.getItem(QUEUE_KEY);
    if (!raw) return [];
    const queue = JSON.parse(raw) as QueuedRequest[];
    const now = Date.now();
    const valid = queue
      .filter(item => now - item.timestamp < MAX_AGE_MS)  // drop stale
      .slice(-MAX_QUEUE_SIZE);                             // keep most recent N
    if (valid.length !== queue.length) {
      // Persist the trimmed version
      await AsyncStorage.setItem(QUEUE_KEY, JSON.stringify(valid));
    }
    return valid;
  } catch {
    return [];
  }
}

