// In a test:
import AsyncStorage from '@react-native-async-storage/async-storage';
import { enqueue, loadQueue } from '../queue';

test('enqueue adds item to persistent storage', async () => {
  const stored: string[] = [];
  (AsyncStorage.getItem as jest.Mock).mockResolvedValue(null);
  (AsyncStorage.setItem as jest.Mock).mockImplementation((_, val) => {
    stored.push(val);
  });

  await enqueue({ id: '1', prompt: 'hello', conversationHistory: [], timestamp: Date.now(), retries: 0 });

  expect(stored).toHaveLength(1);
  const saved = JSON.parse(stored[0]);
  expect(saved[0].prompt).toBe('hello');
});
